import java.util.HashMap;

public class BankingApp {

    private HashMap<String, Double> accounts;

    public BankingApp() {
        accounts = new HashMap<>();
    }

    public void createAccount(String username, double initialBalance) {
        accounts.put(username, initialBalance);
    }

    public double checkBalance(String username) {
        return accounts.getOrDefault(username, 0.0);
    }

    public boolean transferFunds(String fromUsername, String toUsername, double amount) {
        if (accounts.containsKey(fromUsername) && accounts.containsKey(toUsername) && accounts.get(fromUsername) >= amount) {
            accounts.put(fromUsername, accounts.get(fromUsername) - amount);
            accounts.put(toUsername, accounts.get(toUsername) + amount);
            return true;
        }
        return false;
    }
}